import java.net.*;
import java.io.*;
public class HangBug {
    static void connect() throws Exception {
        Socket s = new Socket("example.com", 80);
        InputStream in = s.getInputStream();
        int b;
        while ((b = in.read()) != -1) {  // hangs if server doesn't close
            System.out.print((char)b);
        }
        s.close();
    }
}
